// NuGet: System.Linq.Async
using System.Linq;

// EF Core AsAsyncEnumerable() → LINQ pipeline không buffer
var result = await db.Orders
    .Where(o => o.CreatedAt > cutoff)
    .AsAsyncEnumerable()                        // stream từ DB
    .Where(o => o.Total > 1000)                 // filter sau khi nhận
    .Select(o => new OrderSummary(o.Id, o.Total, o.Status))
    .Take(100)
    .ToListAsync(ct);

// GroupBy với streaming (cẩn thận: GroupBy buffer per key)
var grouped = db.Products.AsAsyncEnumerable()
    .GroupBy(p => p.Category)
    .SelectMany(g => g.Where(p => p.Stock > 0).Take(5));

// Aggregate operators
var totalRevenue = await db.Orders
    .Where(o => o.Status == "completed")
    .AsAsyncEnumerable()
    .SumAsync(o => o.Total, ct);

// Merge nhiều async streams
var merged = AsyncEnumerableEx.Merge(
    GetOrdersStream(tenantA, ct),
    GetOrdersStream(tenantB, ct));  // AsyncEnumerableEx từ System.Reactive

await foreach (var item in merged.WithCancellation(ct))
    await ProcessAsync(item);
